## 1. Mathematical Derivation

### Core Insight
Rotation matrices for 2D rotations form a commutative group:
```
R(θ₁)R(θ₂) = R(θ₁ + θ₂) = R(θ₂)R(θ₁)
```

### Pre-computation Strategy
For base-12 alignment (30° increments):
```
θ_k = k × 30° = k × π/6 radians, k ∈ {0, 1, ..., 11}
```

Store 12 rotation matrices:
```
R[k] = [[cos(θ_k), -sin(θ_k)],
        [sin(θ_k),  cos(θ_k)]]
```

### Incremental Updates
Instead of computing `v' = R(θ)v` directly:
1. Represent current heading as integer index `k` (0-11)
2. For rotation by `n` steps (each 30°):
   ```
   k_new = (k + n) mod 12
   v' = R[k_new] * v
   ```
3. For small incremental rotations (±30°):
   ```
   v' = R[±1] * v_current
   ```

### Complex Number Representation
Let `z = x + iy` represent vector `(x,y)`.
Rotation by θ corresponds to multiplication by `e^(iθ)`:
```
z' = e^(iθ) * z
```
For 30° increments:
```
ω = e^(iπ/6) = cos(π/6) + i sin(π/6) = √3/2 + i/2
R[k] corresponds to ω^k
```

## 2. TypeScript Implementation

```typescript
// Pre-computed rotation tables for 30° increments
const SIN_TABLE: number[] = [
    0.000000, 0.500000, 0.866025, 1.000000, 0.866025, 0.500000,
    0.000000, -0.500000, -0.866025, -1.000000, -0.866025, -0.500000
];

const COS_TABLE: number[] = [
    1.000000, 0.866025, 0.500000, 0.000000, -0.500000, -0.866025,
    -1.000000, -0.866025, -0.500000, -0.000000, 0.500000, 0.866025
];

// Complex number representation (more efficient)
const OMEGA_REAL: number[] = COS_TABLE;
const OMEGA_IMAG: number[] = SIN_TABLE;

class FastRotator {
    private currentIndex: number = 0;

    // Method 1: Direct table lookup
    rotateByIndex(v: [number, number], steps: number): [number, number] {
        const k = (this.currentIndex + steps) % 12;
        if (k < 0) k += 12;

        const cos = COS_TABLE[k];
        const sin = SIN_TABLE[k];

        const [x, y] = v;
        return [
            cos * x - sin * y,
            sin * x + cos * y
        ];
    }

    // Method 2: Incremental update (for continuous rotation)
    rotateIncremental(v: [number, number], direction: number): [number, number] {
        // direction = 1 for +30°, -1 for -30°
        const k = (direction > 0) ? 1 : 11; // 11 = -1 mod 12

        const cos = COS_TABLE[k];
        const sin = SIN_TABLE[k];

        const [x, y] = v;
        const x_new = cos * x - sin * y;
        const y_new = sin * x + cos * y;

        this.currentIndex = (this.currentIndex + direction) % 12;
        if (this.currentIndex < 0) this.currentIndex += 12;

        return [x_new, y_new];
    }

    // Method 3: Complex number multiplication (most efficient)
    rotateComplex(v: [number, number], steps: number): [number, number] {
        const k = (this.currentIndex + steps) % 12;
        if (k < 0) k += 12;

        const re = OMEGA_REAL[k];
        const im = OMEGA_IMAG[k];

        const [x, y] = v;
        return [
            re * x - im * y,
            im * x + re * y
        ];
    }

    // Method 4: Pre-computed matrix multiplication
    private static ROTATION_MATRICES: [number, number, number, number][] = (() => {
        const matrices: [number, number, number, number][] = [];
        for (let k = 0; k < 12; k++) {
            matrices.push([
                COS_TABLE[k], -SIN_TABLE[k],
                SIN_TABLE[k], COS_TABLE[k]
            ]);
        }
        return matrices;
    })();

    rotateMatrix(v: [number, number], steps: number): [number, number] {
        const k = (this.currentIndex + steps) % 12;
        if (k < 0) k += 12;

        const [a, b, c, d] = FastRotator.ROTATION_MATRICES[k];
        const [x, y] = v;

        return [
            a * x + b * y,
            c * x + d * y
        ];
    }

    getCurrentAngle(): number {
        return this.currentIndex * 30; // in degrees
    }

    setCurrentIndex(index: number): void {
        this.currentIndex = ((index % 12) + 12) % 12;
    }
}

// Usage example:
const rotator = new FastRotator();
const vector: [number, number] = [1, 0];

// Rotate by 90° (3 steps of 30°)
const rotated = rotator.rotateByIndex(vector, 3);
console.log(rotated); // Approximately [0, 1]

// Incremental rotation
for (let i = 0; i < 12; i++) {
    const result = rotator.rotateIncremental(vector, 1);
    console.log(`Step ${i}: ${result}`);
}
```

