### Current Approach (Baseline)
```
is_in_view = sqrt(x² + y²) ≤ R && |atan2(y, x)| ≤ θ_max
```

### Optimized Equations

**1. Distance Check (Early Rejection)**
```
reject_if: x² + y² > R²
```

**2. Quadrant-Based Angle Check**
```
// Precompute for θ_max ∈ [0, π]
sin_θ = sin(θ_max)
cos_θ = cos(θ_max)

// For point (x, y) in right half-plane (x ≥ 0)
in_view = y ≤ x·tan_θ && y ≥ -x·tan_θ

// General case using cross product (no trig at runtime)
in_view = |x·sin_θ - y·cos_θ| ≤ 0 && x·cos_θ + y·sin_θ ≥ 0
```

**3. Sector Pre-Filtering (Base-12)**
```
sector = floor(12·atan2(y, x)/(2π)) mod 12  // Precomputed LUT
active_sectors = sectors within [-θ_max, θ_max]
reject_if: sector ∉ active_sectors
```

## 2. TypeScript Implementation

```typescript
interface Point { x: number; y: number; }
interface ViewConfig { radius: number; fov: number; }

class OptimizedViewClassifier {
    private R2: number;
    private sinθ: number;
    private cosθ: number;
    private sectorLUT: Int8Array;
    private activeSectors: Set<number>;

    constructor(config: ViewConfig) {
        const { radius, fov } = config;
        this.R2 = radius * radius;
        this.sinθ = Math.sin(fov / 2);
        this.cosθ = Math.cos(fov / 2);

        // Precompute sector LUT for 1M points
        this.sectorLUT = this.buildSectorLUT();
        this.activeSectors = this.computeActiveSectors(fov);
    }

    private buildSectorLUT(): Int8Array {
        // 4096x4096 grid covering [-R, R] × [-R, R]
        const size = 4096;
        const lut = new Int8Array(size * size);
        const scale = 12 / (2 * Math.PI);

        for (let i = 0; i < size; i++) {
            for (let j = 0; j < size; j++) {
                const x = (i - size/2) / (size/2); // [-1, 1]
                const y = (j - size/2) / (size/2);
                const angle = Math.atan2(y, x);
                lut[i * size + j] = Math.floor((angle + Math.PI) * scale) % 12;
            }
        }
        return lut;
    }

    private computeActiveSectors(fov: number): Set<number> {
        const sectors = new Set<number>();
        const sectorWidth = (2 * Math.PI) / 12;

        for (let s = 0; s < 12; s++) {
            const center = s * sectorWidth - Math.PI;
            if (Math.abs(center) <= fov / 2 + sectorWidth / 2) {
                sectors.add(s);
            }
        }
        return sectors;
    }

    // SIMD-friendly batch processing
    classifyBatch(points: Point[]): boolean[] {
        const results = new Array(points.length).fill(false);
        const chunkSize = 1024; // Process in chunks for better cache locality

        for (let i = 0; i < points.length; i += chunkSize) {
            const end = Math.min(i + chunkSize, points.length);

            for (let j = i; j < end; j++) {
                const { x, y } = points[j];

                // 1. Early distance rejection
                const d2 = x * x + y * y;
                if (d2 > this.R2) continue;

                // 2. Sector pre-filter (branchless)
                const sector = this.getSector(x, y);
                if (!this.activeSectors.has(sector)) continue;

                // 3. Quadrant-based angle check (branch-reduced)
                const cross = Math.abs(x * this.sinθ - y * this.cosθ);
                const dot = x * this.cosθ + y * this.sinθ;

                results[j] = cross <= 1e-9 && dot >= 0;
            }
        }
        return results;
    }

    private getSector(x: number, y: number): number {
        // Quantize to LUT grid (branchless)
        const size = 4096;
        const halfR = this.R2 ** 0.5;
        const ix = Math.min(size-1, Math.max(0, Math.floor((x/halfR + 1) * size/2)));
        const iy = Math.min(size-1, Math.max(0, Math.floor((y/halfR + 1) * size/2)));
        return this.sectorLUT[ix * size + iy];
    }
}

// Usage
const classifier = new OptimizedViewClassifier({ radius: 100, fov: Math.PI/2 });
const points: Point[] = /* 1M points */;
const inView = classifier.classifyBatch(points);
```

