function classifyPoints(points: [number, number][], radius: number, angleThreshold: number): boolean[] {
    const numPoints = points.length;
    const results = new Array<boolean>(numPoints);
    const radiusSquared = radius * radius;
    const angleThresholdCos = Math.cos(angleThreshold);

    for (let i = 0; i < numPoints; i++) {
        const [x, y] = points[i];
        const x2 = x * x;
        const y2 = y * y;
        const distanceSquared = x2 + y2;

        if (distanceSquared > radiusSquared) {
            results[i] = false;
            continue;
        }

        const sector = getSector(x, y);
        const inView = checkSector(x, y, sector, angleThresholdCos);
        results[i] = inView;
    }

    return results;
}

function getSector(x: number, y: number): number {
    if (x >= 0) {
        if (y >= 0) {
            return (y > x) ? 1 : 0; // Quadrant 1
        } else {
            return (y < -x) ? 3 : 2; // Quadrant 4
        }
    } else {
        if (y >= 0) {
            return (y > -x) ? 5 : 4; // Quadrant 2
        } else {
            return (y < x) ? 7 : 6; // Quadrant 3
        }
    }
}

function checkSector(x: number, y: number, sector: number, angleThresholdCos: number): boolean {
    const ratio = Math.abs(y / x);
    const angleCos = Math.sqrt((1 - ratio * ratio) / (1 + ratio * ratio));

    return angleCos >= angleThresholdCos;
}

// Example usage
const points: [number, number][] = [
